		public int GetBossHeadTextureIndex()
		{
			int result = NPCID.Sets.BossHeadTextures[type];
			switch (type)
			{
			case 4:
				if (ai[0] >= 2f)
				{
					result = 1;
				}
				break;
			case 262:
				if (life <= lifeMax / 2)
				{
					result = 12;
				}
				break;
			case 125:
				if (ai[0] >= 3f)
				{
					result = 20;
				}
				break;
			case 126:
				if (ai[0] >= 3f)
				{
					result = 21;
				}
				break;
			case 439:
				if (ai[0] == 5f && alpha == 255)
				{
					result = -1;
				}
				break;
			case 440:
				if (ai[0] != 5f || alpha == 255)
				{
					result = -1;
				}
				break;
			}
			return result;
		}

		public float GetBossHeadRotation()
		{
			float result = 0f;
			switch (type)
			{
			case 68:
			case 262:
				result = rotation;
				break;
			case 35:
			case 127:
				if (ai[1] == 1f || ai[1] == 2f)
				{
					result = rotation;
				}
				break;
			case 345:
				if (ai[0] == 2f)
				{
					result = rotation;
				}
				break;
			}
			return result;
		}

		public SpriteEffects GetBossHeadSpriteEffects()
		{
			SpriteEffects result = SpriteEffects.None;
			int num = type;
			if (num == 491 && spriteDirection == 1)
			{
				result = SpriteEffects.FlipHorizontally;
			}
			return result;
		}

		public int BannerID()
		{
			if (netID >= -10)
			{
				return netID;
			}
			return type;
		}

