				int num2 = 80;
				if (downedPlantBoss)
				{
					num2 += 20;
				}
				if (num < num2)
				{
					float num3 = num2 / num;
					damage = (int)((double)((float)damage * num3) * 0.9);
					if (!flag)
					{
						defense = (int)((float)defense * num3);
						lifeMax = (int)((double)((float)lifeMax * num3) * 1.1);
