		public int checkArmorPenetration(int armorPenetration)
		{
			if (armorPenetration <= 0)
			{
				return 0;
			}
			if (armorPenetration > defense && defense >= 0)
			{
				return defense / 2;
			}
			return armorPenetration / 2;
		}

