					}
				}
				return;
			}
			while (lifeRegenCount <= -120)
			{
				lifeRegenCount += 120;
				int num13 = whoAmI;
				if (realLife >= 0)
				{
					num13 = realLife;
				}
				if (!Main.npc[num13].immortal)
