			{
				if (velocity.X != 0f && velocity.X != oldVelocity.X)
				{
					velocity.X = (0f - oldVelocity.X) * 0.8f;
				}
				if (velocity.Y != 0f && velocity.Y != oldVelocity.Y)
				{
					velocity.Y = (0f - oldVelocity.Y) * 0.8f;
				}
			}
		}

