		private void Collision_MoveWaterOrLavaOld(bool fall, Vector2 cPosition, int cWidth, int cHeight)
		{
			Vector2 vector = velocity;
			velocity = Collision.TileCollision(cPosition, velocity, cWidth, cHeight, fall, fall);
			if (Collision.up)
			{
				velocity.Y = 0.01f;
			}
			Vector2 vector2 = velocity * 0.5f;
			if (velocity.X != vector.X)
			{
				vector2.X = velocity.X;
				collideX = true;
			}
			if (velocity.Y != vector.Y)
			{
				vector2.Y = velocity.Y;
				collideY = true;
			}
			oldPosition = position;
			oldDirection = direction;
			position += vector2;
		}

